import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { validateCreateGroup, validateGetGroup, validateLinkTelegram } from './group.validator';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';

class GroupController {
  private groupService: GroupService;

  constructor() {
    this.groupService = new GroupService();
  }

  async createGroup(req: Request, res: Response): Promise<Response> {
    try {
      const requestData: CreateGroupDTO = validateCreateGroup(req.body);
      const result = await this.groupService.createGroup(requestData);
      return res.status(201).json({ success: true, data: result });
    } catch (error) {
      // Log error and handle response
      return res.status(400).json({ success: false, message: error.message });
    }
  }

  async getGroup(req: Request, res: Response): Promise<Response> {
    try {
      const { id } = validateGetGroup(req.params);
      const result = await this.groupService.getGroup(id);
      return res.status(200).json({ success: true, data: result });
    } catch (error) {
      return res.status(400).json({ success: false, message: error.message });
    }
  }

  async linkTelegram(req: Request, res: Response): Promise<Response> {
    try {
      const requestData: LinkTelegramDTO = validateLinkTelegram(req.body);
      const result = await this.groupService.linkTelegram(req.params.id, requestData);
      return res.status(200).json({ success: true, data: result });
    } catch (error) {
      return res.status(400).json({ success: false, message: error.message });
    }
  }
}

export default new GroupController();

import { GroupRepository } from './group.repository';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';

export class GroupService {
  private groupRepository: GroupRepository;

  constructor() {
    this.groupRepository = new GroupRepository();
  }

  async createGroup(data: CreateGroupDTO) {
    return this.groupRepository.create(data);
  }

  async getGroup(id: string) {
    return this.groupRepository.findById(id);
  }

  async linkTelegram(groupId: string, data: LinkTelegramDTO) {
    return this.groupRepository.linkTelegram(groupId, data.telegramChatId);
  }
}

import { GroupModel } from './group.model';
import { CreateGroupDTO } from './group.dto';

export class GroupRepository {
  async create(data: CreateGroupDTO) {
    const group = new GroupModel(data);
    return group.save();
  }

  async findById(id: string) {
    return GroupModel.findById(id);
  }

  async linkTelegram(groupId: string, telegramChatId: string | undefined) {
    return GroupModel.findByIdAndUpdate(groupId, { telegramChatId }, { new: true });
  }
}

import mongoose, { Schema, Document } from 'mongoose';

export interface IGroup extends Document {
  name: string;
  description: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: { type: String },
  adminId: { type: mongoose.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: mongoose.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now },
});

export const GroupModel = mongoose.model<IGroup>('Group', groupSchema);

import { z } from 'zod';

export const createGroupSchema = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
  adminId: z.string().transform((val) => new mongoose.Types.ObjectId(val)),
  members: z.array(z.string().transform((val) => new mongoose.Types.ObjectId(val))).optional(),
});

export type CreateGroupDTO = z.infer<typeof createGroupSchema>;

export const linkTelegramSchema = z.object({
  telegramChatId: z.string().optional(),
});

export type LinkTelegramDTO = z.infer<typeof linkTelegramSchema>;

import { z } from 'zod';
import { createGroupSchema, linkTelegramSchema } from './group.dto';

export function validateCreateGroup(data: unknown) {
  return createGroupSchema.parse(data);
}

export function validateGetGroup(params: any) {
  return z.object({ id: z.string() }).parse(params);
}

export function validateLinkTelegram(data: unknown) {
  return linkTelegramSchema.parse(data);
}
